    {"hook": "Search an entire website in seconds.", "content": "Type site: followed by the domain and your search term in Google. Example site:nytimes.com climate change finds every article on that topic from that site. Beats using internal site search every time.", "category": "browser", "tool": "Google"},
    {"hook": "Open a closed browser tab from months ago.", "content": "Press Ctrl+Shift+T on Windows or Command+Shift+T on Mac repeatedly. It reopens tabs in the order you closed them, going back through your entire browsing session history.", "category": "browser", "tool": ""},
    {"hook": "Stop websites from asking for notifications.", "content": "In Chrome, go to Settings, Privacy and Security, Site Settings, Notifications. Select Don't allow sites to send notifications. No more permission popups interrupting your browsing.", "category": "browser", "tool": "Chrome"},
    {"hook": "Make any PDF editable for free.", "content": "Upload any PDF to Google Drive, right-click, open with Google Docs. It converts the PDF to an editable document. Edit text, fix typos, then export back to PDF. No paid subscription needed.", "category": "productivity", "tool": "Google Drive"},
    {"hook": "Schedule emails to send later in Gmail.", "content": "Instead of sending now, click the dropdown arrow next to the Send button. Choose Schedule Send and pick a date and time. Perfect for late night work that should arrive in business hours.", "category": "productivity", "tool": "Gmail"},
