    {"hook": "Access ChatGPT from any app with a keyboard shortcut.", "content": "Install the MacGPT or Windows ChatGPT desktop app. Press a global shortcut and a chat window opens over any app. Ask questions without switching context or opening a browser.", "category": "ai", "tool": "MacGPT"},
