    {"hook": "Stop notifications from interrupting your focus.", "content": "Enable Focus Mode on iPhone or Do Not Disturb on Android. Schedule it to activate during work hours. Only calls from favorites get through. Check notifications on your own schedule.", "category": "phone", "tool": ""},
